DDL:
DROP TABLE IF EXISTS DIM_COUNTRY CASCADE;
CREATE TABLE DIM_COUNTRY (
	COUNTRY_ID BIGINT PRIMARY KEY,
	COUNTRY_NAME VARCHAR(20)
);

DROP TABLE IF EXISTS DIM_STATE CASCADE;
CREATE TABLE DIM_STATE (
	STATE_ID BIGINT PRIMARY KEY,
	COUNTRY_ID BIGINT,
	STATE_NAME VARCHAR(100),
	FOREIGN KEY (COUNTRY_ID) REFERENCES DIM_COUNTRY (COUNTRY_ID)
);

DROP TABLE IF EXISTS DIM_DISTRICT CASCADE;
CREATE TABLE DIM_DISTRICT (
	DISTRICT_ID BIGINT PRIMARY KEY,
	STATE_ID BIGINT,
	DISTRICT_NAME VARCHAR(50),
	FOREIGN KEY (STATE_ID) REFERENCES DIM_STATE (STATE_ID)
);

DROP TABLE IF EXISTS DIM_SCHOOL CASCADE;
CREATE TABLE DIM_SCHOOL (
	SCHOOL_ID BIGINT PRIMARY KEY,
	DISTRICT_ID BIGINT,
	UNIQUE_SCHOOL_ID BIGINT,
	FOREIGN KEY (DISTRICT_ID) REFERENCES DIM_DISTRICT (DISTRICT_ID)
);

DROP TABLE IF EXISTS DIM_YEAR CASCADE;
CREATE TABLE DIM_YEAR (
	YEAR_ID INTEGER PRIMARY KEY,
	ACADEMIC_YEAR INTEGER
);

DROP TABLE IF EXISTS FACT_SCHOOL_RESOURCES CASCADE;
CREATE TABLE FACT_SCHOOL_RESOURCES (
	RESOURCE_ID BIGINT PRIMARY KEY,
	SCHOOL_ID BIGINT,
	YEAR_ID INTEGER,
	SCHOOLS_RECEIVED_FULL_SET_OF_TEXTBOOKS_IN_CURRENT_ACADEMIC_YEAR INTEGER,
	SCHOOLS_RECEIVED_GRADED_SUPPLEMENTARY_MATERIAL_IN_PREVIOUS_ACADEMIC_YEAR INTEGER,
	FOREIGN KEY (SCHOOL_ID) REFERENCES DIM_SCHOOL (SCHOOL_ID),
	FOREIGN KEY (YEAR_ID) REFERENCES DIM_YEAR (YEAR_ID)
);

DROP TABLE IF EXISTS FACT_STUDENT_ENROLLMENT CASCADE;
CREATE TABLE FACT_STUDENT_ENROLLMENT (
	ENROLLMENT_ID BIGINT PRIMARY KEY,
	SCHOOL_ID BIGINT,
	YEAR_ID INTEGER,
	STUDENT_COUNT DOUBLE PRECISION,
	FOREIGN KEY (SCHOOL_ID) REFERENCES DIM_SCHOOL (SCHOOL_ID),
	FOREIGN KEY (YEAR_ID) REFERENCES DIM_YEAR (YEAR_ID)
);

DROP TABLE IF EXISTS FACT_SPECIAL_TRAINING CASCADE;
CREATE TABLE FACT_SPECIAL_TRAINING (
	TRAINING_ID BIGINT PRIMARY KEY,
	SCHOOL_ID BIGINT,
	YEAR_ID INTEGER,
	STUDENTS_ATTENDING_SPECIAL_TRAINING VARCHAR(50),
	FOREIGN KEY (SCHOOL_ID) REFERENCES DIM_SCHOOL (SCHOOL_ID),
	FOREIGN KEY (YEAR_ID) REFERENCES DIM_YEAR (YEAR_ID)
);

DROP TABLE IF EXISTS FACT_SCHOOL_FINANCES CASCADE;
CREATE TABLE FACT_SCHOOL_FINANCES (
	FINANCE_ID BIGINT PRIMARY KEY,
	SCHOOL_ID BIGINT,
	YEAR_ID INTEGER,
	SCHOOL_GRANT_RECEIVED DOUBLE PRECISION,
	UTILIZATION_OF_SCHOOL_GRANT DOUBLE PRECISION,
	FOREIGN KEY (SCHOOL_ID) REFERENCES DIM_SCHOOL (SCHOOL_ID),
	FOREIGN KEY (YEAR_ID) REFERENCES DIM_YEAR (YEAR_ID)
);
